import secrets
import hashlib
import time
from functools import wraps

# In-memory storage
users_db = {}
tokens_db = {}

# Token expiration time (in seconds)
TOKEN_EXPIRATION = 3600  # 1 hour

def hash_password(password):
    return hashlib.sha256(password.encode()).hexdigest()

def register_user(username, password):
    if username in users_db:
        return {"success": False, "message": "User already exists"}
    
    users_db[username] = {
        "password": hash_password(password),
        "created_at": time.time()
    }
    return {"success": True, "message": "User registered successfully"}

def generate_token():
    return secrets.token_urlsafe(32)

def login(username, password):
    if username not in users_db:
        return {"success": False, "message": "Invalid credentials"}
    
    if users_db[username]["password"] != hash_password(password):
        return {"success": False, "message": "Invalid credentials"}
    
    token = generate_token()
    tokens_db[token] = {
        "username": username,
        "created_at": time.time()
    }
    
    return {"success": True, "token": token, "message": "Login successful"}

def verify_token(token):
    if token not in tokens_db:
        return {"valid": False, "message": "Invalid token"}
    
    token_data = tokens_db[token]
    current_time = time.time()
    
    if current_time - token_data["created_at"] > TOKEN_EXPIRATION:
        del tokens_db[token]
        return {"valid": False, "message": "Token expired"}
    
    return {"valid": True, "username": token_data["username"]}

def logout(token):
    if token in tokens_db:
        del tokens_db[token]
        return {"success": True, "message": "Logged out successfully"}
    return {"success": False, "message": "Invalid token"}

def require_auth(func):
    @wraps(func)
    def wrapper(token, *args, **kwargs):
        verification = verify_token(token)
        if not verification["valid"]:
            return {"error": verification["message"]}
        return func(verification["username"], *args, **kwargs)
    return wrapper

@require_auth
def protected_endpoint(username, data=None):
    return {
        "success": True,
        "message": f"Hello {username}, you have access to this protected resource",
        "data": data
    }

@require_auth
def get_user_profile(username):
    return {
        "success": True,
        "username": username,
        "created_at": users_db[username]["created_at"]
    }

if __name__ == "__main__":
    print("=== API Authentication System Demo ===\n")
    
    print("1. Registering user 'alice'")
    result = register_user("alice", "password123")
