    print("2. Registering user 'bob'")
    result = register_user("bob", "secret456")
    print(f"   {result}\n")
    
    print("3. Attempting to login with wrong password")
    result = login("alice", "wrongpassword")
    print(f"   {result}\n")
    
    print("4. Login with correct credentials")
    result = login("alice", "password123")
    print(f"   {result}\n")
    
    if result["success"]:
        token = result["token"]
        
        print(f"5. Accessing protected endpoint with token")
        response = protected_endpoint(token, data={"item": "secret data"})
        print(f"   {response}\n")
        
        print(f"6. Getting user profile")
        response = get_user_profile(token)
        print(f"   {response}\n")
        
        print(f"7. Accessing with invalid token")
        response = protected_endpoint("invalid_token_123")
        print(f"   {response}\n")
        
        print(f"8. Logging out")
        result = logout(token)
        print(f"   {result}\n")
        
        print(f"9. Trying to access after logout")
        response = protected_endpoint(token)
